  ('real-estate-moex-00415', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關現行民法代理制度之介紹，下列何者錯誤？', '["未經本人事前同意之自己代理，對於本人而言，係無效之代理行為", "民法第169條表見代理效力之發生，須無本人之授予代理權為其要件", "間接代理人之代理行為不會對本人直接發生效力", "代理人為代理行為時，被相對人詐欺，本人得自行撤銷該代理行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
