  ('real-estate-moex-00418', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於民法第74條暴利行為之規定，下列敘述何者正確？', '["當事人無論於財產給付前或給付後，均得聲請撤銷該暴利行為", "撤銷權自該法律行為成立時起一年內不行使，罹於消滅時效而消滅", "行使暴利行為之撤銷權時，應以意思表示向相對人為之", "暴利行為自始當然無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00419', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非法律明文規定屬於連帶債務之性質？', '["合夥財產不足清償合夥債務時，各合夥人對於該不足額之債務", "數人共同不法侵害他人權利所生之損害賠償債務", "共同繼承人對於被繼承人，於繼承所得遺產限度內之遺產債務", "共有人對於他共有人因分割而得之物，所負之擔保責任債務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00420', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非屬贈與人或其繼承人，得主張撤銷贈與契約之原因？', '["附有負擔之贈與，贈與人已為給付而受贈人因過失不履行其負擔者", "受贈人對於贈與人有扶養義務而不履行義務者", "受贈人因故意不法行為致贈與人死亡者", "定期給付之贈與，而受贈人已死亡者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00421', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於共有不動產分管契約之敘述，下列何者正確？', '["分管契約應以共有人半數以上及其應有部分合計過半數，或應有部分合計逾三分之二之同意訂 定之", "分管契約訂定後，若因情事變更難以繼續時，法院得因任何共有人之聲請，以裁定變更之", "共有人對於分管契約無法達成協議時，得訴請法院裁判定分管方式", "分管契約訂定後，對於應有部分之受讓人於受讓時知悉其情事者，亦具有效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00422', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙結婚，生有三個女兒丙、丁、戊。丙因未婚生有二子庚及辛，曾與其母乙發生重大爭吵及 言語侮辱情事，而遭甲表示剝奪其繼承權。丁則於甲生前即已向甲表示，當甲百年後將拋棄繼承 權。設甲死亡時留有遺產現金600萬元，並未立有遺囑。問:甲之遺產依法應如何分配？', '["乙、丙、丁、戊各150萬元", "乙、戊各200萬元，庚、辛各100萬元", "乙、丁、戊各150萬元，庚、辛各75萬元", "乙、戊各300萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00423', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於限定繼承之敘述，下列何者正確？', '["限定繼承係指繼承人自繼承開始時，僅承受被繼承人財產上之權利，而不繼承其債務", "繼承人縱未依法開具遺產清冊陳報法院，並不當然喪失限定繼承之利益", "繼承人隱匿被繼承人之遺產而情節重大者，仍可主張限定繼承之利益", "繼承人應先對受遺贈人交付遺贈，其次償還優先權之債務，再清償普通債務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00424', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於夫妻法定財產制之規定，下列敘述何者正確？', '["夫或妻之財產分為婚前財產與婚後財產，婚前財產由夫妻各自所有，婚後財產則由夫妻共有", "夫或妻於婚姻關係存續中就其婚後財產所為之無償行為，應將該財產追加計算，視為現存之婚 後財產", "夫或妻各自管理、使用、收益及處分其婚前及婚後財產，並各自對其債務負清償之責", "剩餘財產差額分配請求權屬一身專屬性之權利，請求權人自法定財產制關係消滅時起，二年間 不行使而消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00425', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其A地設定地上權予乙，乙於A土地上興建B屋一棟。其後甲為貸款擔保而將其A地設定 抵押權予丙，乙亦因其貸款擔保而將B屋設定抵押權予丁。下列敘述何者正確？', '["若丁實行抵押權拍賣B屋時，A地所有權應併付拍賣之", "若丁實行抵押權拍賣B屋時，地上權應併付拍賣之", "若丙實行抵押權拍賣A地所有權時，B屋應併付拍賣之", "若丙實行抵押權拍賣A地所有權時，地上權應併付拍賣之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00426', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲無權占有乙之土地種植果樹，其果實歸屬於何人？', '["果實在與果樹分離前或分離後，均屬於甲所有", "果實在與果樹分離前或分離後，均屬於乙所有", "果實在與果樹分離前屬於甲所有，分離後屬於乙所有", "果實在與果樹分離前屬於乙所有，分離後屬於甲所有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00427', 'real-estate', 'real-estate-moex-111-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '特定物買賣，若因物有瑕疵而出賣人依法應負物之瑕疵擔保責任時，下列何者非買受人依法所得 主張之權利？', '["解除買賣契約", "請求減少買賣價金", "請求另行交付無瑕疵之物", "故意不告知瑕疵時，請求損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:35+00:00", "source_pdf_sha1": "66a7d11c082e", "answer_pdf_sha1": "09a704bed47f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年專技人員高等考試建築師、31類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL);
